#include <stdio.h>
#define MOD 1000000007
int main() {
    int N, Q, K;
    scanf("%d %d %d", &N, &Q, &K);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    for (int i = 0; i < Q; i++) {
        int L, R, P;
        scanf("%d %d %d", &L, &R, &P);
        long long total = 0;
        for (int j = L - 1; j < R; j++) {
            for (int k = j; k < R; k++) {
                long long gen = ((A[j] + P - 1) / P) * ((A[k] + P - 1) / P);
                total = (total + gen) % MOD;
            }
        }
        printf("%lld\n", total);
    }
    return 0;
}

