const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;
const nextLine = () => lines[idx++];
const nextInts = () => nextLine().split(' ').map(x => parseInt(x));
const [N, Q, K] = nextInts();
const A = nextInts();
for (let i = 0; i < Q; i++) {
    const [L, R, P] = nextInts();
    let total = 0;
    for (let j = L - 1; j < R; j++) {
        for (let k = j; k < R; k++) {
            const gen = Math.floor((A[j] + P - 1) / P) * Math.floor((A[k] + P - 1) / P);
            total = (total + gen) % MOD;
        }
    }
    console.log(total);
}
